qry:select.qry:xquery:
for $r in SQL(' SELECT
PER01_PERSONAL.d_ape_y_nom, PER02_PERSONAL_EMP.e_numero_legajo, ORG12_NACIONALID.d_nacionalidad, PER01_PERSONAL.c_sexo, ORG22_EST_CIVIL.d_estado_civil, PER01_PERSONAL.c_nro_cuil, PER01_PERSONAL.f_nacim, ORG03_FUNCIONES.d_funcion, PER02_PERSONAL_EMP.f_ingreso, PER11_TIPOS_PERS.d_tipo_personal, ORG18_CATEGORIAS.c_categoria, ORG18_CATEGORIAS.d_categoria, ORG18_CATEGORIAS.n_valor_hora, ORG18_CONVENIOS.c_convenio, ORG18_CONVENIOS.d_convenio FROM PER02_PERSONAL_EMP, PER01_PERSONAL, ORG12_NACIONALID, ORG22_EST_CIVIL, ORG03_FUNCIONES, PER11_TIPOS_PERS, ORG18_CATEGORIAS, ORG18_CONVENIOS JOIN PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal, PER01_PERSONAL.oi_nacionalidad LEFT OUTER ORG12_NACIONALID.oi_nacionalidad, PER01_PERSONAL.oi_estado_civil LEFT OUTER ORG22_EST_CIVIL.oi_estado_civil, PER02_PERSONAL_EMP.oi_funcion LEFT OUTER ORG03_FUNCIONES.oi_funcion, PER02_PERSONAL_EMP.oi_tipo_personal LEFT OUTER PER11_TIPOS_PERS.oi_tipo_personal, PER02_PERSONAL_EMP.oi_categoria_ult LEFT OUTER ORG18_CATEGORIAS.oi_categoria, ORG18_CATEGORIAS.oi_convenio LEFT OUTER ORG18_CONVENIOS.oi_convenio WHERE PER02_PERSONAL_EMP.oi_personal_emp = {#SOURCE:@oi_per}
')/ROWS/ROW

